/**
 * Removes an entire column from the table.
 *
 * @param columnKey  the column key (<code>null</code> not permitted).
 *
 * @throws UnknownKeyException if <code>columnKey</code> is not recognised.
 *
 * @see #removeRow(Comparable)
 */
public void removeColumn(Comparable columnKey) {
    int index = getColumnIndex(columnKey);
    if (index < 0) {
        throw new UnknownKeyException("Column key (" + columnKey
                + ") not recognised.");
    }
    Iterator iterator = this.rows.iterator();
    while (iterator.hasNext()) {
        KeyedObjects rowData = (KeyedObjects) iterator.next();
            rowData.removeValue(columnKey);
    }
    this.columnKeys.remove(columnKey);

    // Check if any rows are now completely empty and remove them
    for (int r = this.rows.size() - 1; r >= 0; r--) {
        KeyedObjects rowData = (KeyedObjects) this.rows.get(r);
        if (rowData.getItemCount() == 0) {
            // This row is empty, remove it
            this.rowKeys.remove(r);
            this.rows.remove(r);
        }
    }
}

